   "source": [
    "# draw a plot with \"Review_Date\" as the x axis and \"Rating\" as the y axis, and add a point for each data point\n",
    "ggplot(chocolateData, aes(x= Review_Date, y = Rating)) + geom_point()"
   ]
  },
