   "source": [
    "It looks like chocolate bars with very high cocoa percents tend to get lower ratings. Let's see if that's the case by drawing a helpful graph. At this point, you know enough to make this graph yourself. Show me what you got! :)"
   ]
  },
  {
   "cell_type": "code",
   "execution_count": 7,
   "id": "167ae41d",
   "metadata": {
    "_cell_guid": "0907ef6f-1b62-4e6b-b25e-51cbf57e480b",
    "_uuid": "4ab98fa4f33da0042b9ac020e0a4c7423d85fd0c",
    "execution": {
     "iopub.execute_input": "2026-05-11T11:14:02.682772Z",
     "iopub.status.busy": "2026-05-11T11:14:02.679718Z",
     "iopub.status.idle": "2026-05-11T11:14:02.717557Z",
     "shell.execute_reply": "2026-05-11T11:14:02.714765Z"
    },
    "papermill": {
     "duration": 0.07483,
     "end_time": "2026-05-11T11:14:02.721167",
     "exception": false,
     "start_time": "2026-05-11T11:14:02.646337",
     "status": "completed"
    },
    "tags": []
   },
   "outputs": [],
   "source": [
    "# Your turn!\n",
    "\n",
    "# Plot the relationship between cocoa percentage and ratings, using whichever geom (or multiple geoms) you like.\n",
    "cocoaVsRating <- ggplot(chocolateData, aes(x = Cocoa_Percent, y = Rating)) + \n",
    "    geom_point(alpha = 0.5) +\n",
    "    geom_jitter(width = 1, height = 0.2) +\n",
    "    geom_smooth(method = 'loess', color = 'red', se = TRUE) +\n",
    "    labs(title = \"Chocolate Rating vs Cocoa Percentage\",\n",
    "         x = \"Cocoa Percentage\",\n",
    "         y = \"Rating\") +\n",
    "    theme_minimal()\n",
    "# Note that, if you use geom_smooth(), a linear model may not be the best fit for the data!"
   ]
  },
