    "# Your turn!\n",
    "\n",
    "# Make & save a data_frame with the average and sd Cocoa_Percent by the year the reviews were written\n",
    "averageCocoaByYear <- chocolateData %>%\n",
    "    group_by(Review_Date) %>%\n",
    "    summarise(averageCocoaPercent = mean(Cocoa_Percent, na.rm = TRUE),\n",
    "              sdCocoaPercent = sd(Cocoa_Percent, na.rm = TRUE))\n",
    "# Plot the data_frame you've made using your choice of geom(s)\n",
    "cocoaPercentPlot <- ggplot(averageCocoaByYear, aes(x = Review_Date, y = averageCocoaPercent)) + \n",
    "    geom_point(size = 3, color = \"blue\") +\n",
    "    geom_line(color = \"blue\", size = 1) +\n",
    "    geom_errorbar(aes(ymin = averageCocoaPercent - sdCocoaPercent,\n",
    "                       ymax = averageCocoaPercent + sdCocoaPercent),\n",
    "                   width = 0.5, color = \"blue\", alpha = 0.6) +\n",
    "    ggtitle(\"Average Cocoa Percentage Over Time (with Standard Deviation)\") +\n",
    "    xlab(\"Review Year\") +\n",
    "    ylab(\"Average Cocoa Percentage\") +\n",
    "    theme_minimal() +\n",
    "    theme(plot.title = element_text(size = 14, face = \"bold\", hjust = 0.5))\n",
    "# Save your plot to the output\n",
    "ggsave(\"average_cocoa_percent_over_time.png\",\n",
    "       plot = cocoaPercentPlot,\n",
    "       height = 6, width = 10, units = \"in\")\n",
    "# Extra credit: Add a title to your plot. You may find the function ggtitle() helpful"
   ]
  },
